class InternalLevel:
    """Physical storage layer - manages data on disk"""
    def __init__(self):
        self.storage = {
            "students": [[1, "Amit", 20], [2, "Priya", 19]],
            "courses": [[101, "DBMS", 4], [102, "Python", 3]]
        }

    def read_page(self, table, page_num):
        print(f"[Internal] Reading page {page_num} from disk for {table}")
        return self.storage.get(table, [])

    def write_page(self, table, data):
        print(f"[Internal] Writing data to disk for {table}")
        self.storage[table] = data

class ConceptualLevel:
    """Logical layer - defines schema and relationships"""
    def __init__(self, internal):
        self.internal = internal
        self.schema = {
            "students": {"id": "INT", "name": "STRING", "age": "INT"},
            "courses": {"course_id": "INT", "title": "STRING", "credits": "INT"}
        }

    def validate_query(self, query):
        print(f"[Conceptual] Validating query against schema")
        return True

    def optimize(self, query):
        print(f"[Conceptual] Query optimization: Using index on primary key")
        return "OPTIMIZED_QUERY"

class ExternalLevel:
    """User view layer - presents data to users"""
    def __init__(self, conceptual):
        self.conceptual = conceptual

    def receive_query(self, query):
        print(f"[External] User submitted: {query}")
        return query

    def format_result(self, data, view_type="table"):
        print(f"[External] Formatting {len(data)} rows for user view")
        return data

# Demonstrate architecture flow
print("=== DBMS Three-Level Architecture Demo ===\n")

external = None
conceptual = None
internal = InternalLevel()

# Build the architecture
conceptual = ConceptualLevel(internal)
external = ExternalLevel(conceptual)

# User query flow
query = "SELECT * FROM students WHERE id = 1"
external.receive_query(query)
conceptual.validate_query(query)
conceptual.optimize(query)
data = internal.read_page("students", 0)
external.format_result(data)
